form:Form.form:Scripts:
		function ClearEmpresa()
{
	Ctrl("OI_CLASE_ORG").SetCValue("");                     

}
  function OnLoad()
{                              
	if  (Ctrl("Estado").GetXValue()=="Sin Errores") 
	{ 	CtrlEnabled("btn_logTCO",false	);          }
	else
	{ 	CtrlEnabled("btn_logTCO",true);              }
}






function EJECUTAR_CLICK()
{                             
	if (Ctrl("OI_CLASE_ORG").GetXValue()=="") { alert("La Empresa es Requerida."); return false; }      
	if (Ctrl("oi_aniomes").GetXValue()=="") { alert("Mes/Año es Requerido."); return false; }

	if (!Ctrl("main").Validate()) return false;

var mdx ="";
var d_org ="";
var c_emp ="";
var c_año ="";
var c_mes ="";              


var d_org = Ctrl("OI_CLASE_ORG").GetText(1);
var c_emp =Ctrl("OI_CLASE_ORG").GetCValue();
var c_anio =Ctrl("oi_aniomes").GetCValue().split("/")[1];
var c_mes =Ctrl("oi_aniomes").GetCValue();              

mdx =Ctrl("MDXqry").GetCValue()  ;	

   var a;

for ( a= 1; a <20 ; a++)
{ 
mdx = mdx.replace("ORG_REEMPLAZO",d_org)  ;
//mdx = mdx.replace("EMPRESA_REEMPLAZO",c_emp)  ;
mdx = mdx.replace("ANIOMES_REEMPLAZO1",c_anio)  ;
mdx = mdx.replace("ANIOMES_REEMPLAZO2",c_mes)  ;
    }
//alert(mdx);

	Ctrl("mdx").SetXValue(mdx);
	Ctrl("main").DoEvent("EJECUTAR_CLICK");
	return true;
}  


function showLogTCO()
{         

var modTco =Ctrl("Tco_Modulo").GetCValue() ;
var Tco_acc_flow =Ctrl("Tco_accion_flow").GetCValue() ;
	openNewFlowWait("NucleusRH.Base.Indicadores.logTCO.flow","initialize","<param modulo=\""+modTco + "\" />",new ObjtectResult(),"L");
}

function ObjtectResult()
{        
	this.processResult= function(xmlin){}
}
